  gas_fc |>
    filter(.model %in% c("snaive", "drift")) |>
    accuracy(aus_production),
  gas_fc_bc |>
    accuracy(aus_production)
) |>
  select(.model, RMSE, MAE, MASE, RMSSE) |>
  arrange(RMSSE)
```

